BlockGoodsManager = {}
BlockGoodsManager.Pools = {}

function BlockGoodsManager:addBlockGoodsToPools(item)
    local pool = BlockGoodsManager.Pools[item.poolId]
    if not pool then
        BlockGoodsManager.Pools[item.poolId] = {}
    end
    table.insert(BlockGoodsManager.Pools[item.poolId], item)
end

--随机取物品
function BlockGoodsManager:randomGoods(poolId, num)
    local pool = BlockGoodsManager.Pools[tonumber(poolId)]
    if not pool then
        print("can't find block goods pool [poolId]:" .. poolId)
        return {}
    end
    local result = RandomUtil:randomItemByWeight(num, pool, false)
    return result
end